const DEFAULT_PROVIDER_ENTRY = {
  url: "",
  anthropicCompliant: false
};

function deepMerge(target, source) {
  for (const key of Object.keys(source)) {
    if (source[key] instanceof Object && !Array.isArray(source[key])) {
      if (!target[key]) Object.assign(target, { [key]: {} });
      deepMerge(target[key], source[key]);
      continue;
    }
    if (target[key] === undefined) {
      Object.assign(target, { [key]: source[key] });
    }
  }
}

export function ensureCompleteConfig(existingRaw) {
  const merged = JSON.parse(JSON.stringify(existingRaw || {}));

  // Migrate legacy daemon properties
  if (merged.daemon) {
    if (merged.daemon.healthCheckTimeout !== undefined) {
      merged.daemon.healthCheckTimeoutMs = merged.daemon.healthCheckTimeout;
      delete merged.daemon.healthCheckTimeout;
    }
    if (merged.daemon.pollInterval !== undefined) {
      merged.daemon.pollIntervalMs = merged.daemon.pollInterval;
      delete merged.daemon.pollInterval;
    }
  }

  deepMerge(merged, DEFAULT_RAW_CONFIG);
  return merged;
}

export function ensureCompleteProviders(existingRaw) {
  const merged = JSON.parse(JSON.stringify(existingRaw || {}));

  // Detect format and convert v1 → v2 if needed
  const format = detectFormat(merged);
  if (format === 'v1') {
    return convertV1ToV2(merged);
  }

  // v2 format: merge defaults into providers object
  if (!merged.providers || typeof merged.providers !== 'object' || Array.isArray(merged.providers)) {
    merged.providers = JSON.parse(JSON.stringify(DEFAULT_RAW_PROVIDERS.providers));
  }

  if (merged.providers && typeof merged.providers === 'object' && !Array.isArray(merged.providers)) {
    for (const [id, cfg] of Object.entries(merged.providers)) {
      deepMerge(cfg, DEFAULT_PROVIDER_ENTRY);
    }
  }

  // Ensure routes section exists with all sub-sections
  if (!merged.routes) merged.routes = {};
  if (!merged.routes.models) merged.routes.models = {};
  if (!merged.routes.properties) merged.routes.properties = {};
  if (!merged.routes.payloadSize) merged.routes.payloadSize = {};

  return merged;
}

import http from 'http';
import https from 'https';
import { randomBytes } from 'crypto';
import { URL } from 'url';
import { ProxyResponseContext } from './types.js';
import { filterResponseHeaders } from './headers.js';
import { SseResponseTransformer } from './sse-transformer.js';

/**
 * Generate a unique cc-bridge error ID.
 * Format: ccb-{timestamp_base36}-{random_hex}
 */
function generateErrorId() {
  return `ccb-${Date.now().toString(36)}-${randomBytes(4).toString('hex')}`;
}

/**
 * Sleep for ms, resolving early if the client disconnects.
 */
function sleepAbortable(ms, ctx) {
  return new Promise((resolve) => {
    const timer = setTimeout(resolve, ms);
    const onGone = () => { clearTimeout(timer); resolve(); };
    ctx.req.on('close', onGone);
    ctx.req.on('aborted', onGone);
  });
}

/**
 * Check if an upstream TCP error is retryable.
 */
function isRetryableTcpError(err, retryConfig) {
  return retryConfig.retryOnTcpErrors.includes(err.code);
}

/**
 * Check if an HTTP status code is retryable.
 */
function isRetryableStatusCode(statusCode, retryConfig) {
  return retryConfig.retryOnStatusCodes.includes(statusCode);
}

/**
 * Check if a response body matches any retryable body pattern.
 */
function isRetryableBody(bodyStr, retryConfig) {
  for (const pattern of retryConfig.retryOnBodyPatterns) {
    try {
      if (new RegExp(pattern).test(bodyStr)) return true;
    } catch { /* invalid regex — skip */ }
  }
  return false;
}

/**
 * Forward the processed request to the upstream provider with retry support.
 *
 * Selects http or https transport based on targetBase protocol, handles
 * timeout, error forwarding, and pipes the response through SSE
 * transformation if needed.
 *
 * @param {object} params
 * @param {ProxyRequestContext} params.ctx - Request context with routing applied
 * @param {function} params.handleResponseEnd - Callback for completed responses
 * @param {ErrorReporter} params.errorReporter - Error reporter
 * @param {function} params.getConfig - Config accessor
 * @param {RoutingPolicy} params.policy - Active routing policy (for fallback resolution)
 * @param {function} params.emit - Emit function for logging fallback events
 */
export function forwardToUpstream({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit }) {
  const retryConfig = getConfig().retry;
  if (retryConfig.maxAttempts > 0) {
    forwardWithRetry({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, retryConfig, attempt: 0 });
  } else {
    singleForwardAttempt({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, retryConfig: null, onRetryNeeded: null });
  }
}

/**
 * Retry wrapper around singleForwardAttempt with exponential backoff.
 */
function forwardWithRetry({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, retryConfig, attempt }) {
  let settled = false;

  const retryState = {
    shouldRetry: false,
    retryReason: '',
  };

  singleForwardAttempt({
    ctx,
    handleResponseEnd: ({ resCtx, resChunks }) => {
      if (!retryState.shouldRetry) {
        handleResponseEnd({ resCtx, resChunks });
        return;
      }
      settled = true;
      attemptRetry();
    },
    errorReporter,
    getConfig,
    policy,
    extensions,
    emit,
    retryConfig,
    onTcpError: (err) => {
      if (isRetryableTcpError(err, retryConfig) && attempt < retryConfig.maxAttempts) {
        retryState.shouldRetry = true;
        retryState.retryReason = err.code;
        settled = true;
        attemptRetry();
        return true; // signal: suppress error response, retry instead
      }
      // Retries exhausted — try fallback before sending proxy_error
      if (extensions && extensions.hasFallback && extensions.shouldAttemptFallbackForTcpError({ matchedRule: ctx.matchedRule, fallbackDepth: ctx.fallbackDepth })) {
        settled = true;
        emit(`[#${ctx.id}] Retry exhausted (${retryConfig.maxAttempts} attempts), falling back: ${err.code}`, ctx.sessionId).catch(() => {});
        attemptFallbackFromTcpError(ctx, extensions, handleResponseEnd, errorReporter, getConfig, policy, emit);
        return true; // suppress normal error handling
      }
      return false;
    },
    onUpstreamResponse: (statusCode, bodyStr) => {
      if (attempt >= retryConfig.maxAttempts) return false;
      if (isRetryableStatusCode(statusCode, retryConfig)) {
        retryState.shouldRetry = true;
        retryState.retryReason = `HTTP ${statusCode}`;
        return true;
      }
      if (isRetryableBody(bodyStr, retryConfig)) {
        retryState.shouldRetry = true;
        retryState.retryReason = `body pattern match`;
        return true;
      }
      return false;
    },
    onRetryNeeded: () => {
      settled = true;
      attemptRetry();
    },
  });

  function attemptRetry() {
    if (ctx.clientAborted) {
      emit(`[#${ctx.id}] Retry aborted (client gone) after attempt ${attempt}`, ctx.sessionId).catch(() => {});
      return;
    }

    const nextAttempt = attempt + 1;
    const delay = Math.min(retryConfig.baseDelayMs * Math.pow(2, attempt), retryConfig.maxDelayMs);

    emit(`[#${ctx.id}] Retrying (attempt ${nextAttempt}/${retryConfig.maxAttempts}, ${delay}ms): ${retryState.retryReason}`, ctx.sessionId).catch(() => {});

    sleepAbortable(delay, ctx).then(() => {
      if (ctx.clientAborted) {
        emit(`[#${ctx.id}] Retry aborted (client gone) during backoff`, ctx.sessionId).catch(() => {});
        return;
      }
      forwardWithRetry({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, retryConfig, attempt: nextAttempt });
    });
  }
}

/**
 * Attempt fallback after retry-exhausted TCP error.
 */
function attemptFallbackFromTcpError(ctx, extensions, handleResponseEnd, errorReporter, getConfig, policy, emit) {
  const fallbackResult = extensions.buildFallbackRequest({ originalBody: ctx.originalBody, matchedRule: ctx.matchedRule, policy, routedHeaders: ctx.routedHeaders });
  if (!fallbackResult) return;

  const fallbackCtx = ctx.withRouting({
    routeLabel: fallbackResult.label,
    reqModel: ctx.reqModel,
    sessionId: ctx.sessionId,
    routedHeaders: fallbackResult.routedHeaders,
    forwardBody: fallbackResult.forwardBody,
    targetBase: fallbackResult.targetBase,
    isCustom: true,
    rawBody: ctx.rawBody,
    originalBody: ctx.originalBody,
    sanitizationReport: fallbackResult.sanitizationReport,
    fallbackDepth: ctx.fallbackDepth + 1,
    matchedRule: null
  });

  forwardToUpstream({ ctx: fallbackCtx, handleResponseEnd, errorReporter, getConfig, policy, emit });
}

/**
 * Single attempt to forward the request upstream.
 *
 * @param {object} params
 * @param {function|null} params.onTcpError - Called on TCP error; return true to suppress error response
 * @param {function|null} params.onUpstreamResponse - Called with (statusCode, bodyStr) for 4xx/5xx; return true to buffer instead of stream
 */
function singleForwardAttempt({ ctx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, retryConfig, onTcpError, onUpstreamResponse, onRetryNeeded }) {
  const target = new URL(ctx.targetBase + (ctx.req.url ?? '/'));
  const finalHeaders = { ...ctx.routedHeaders, host: target.host, 'content-length': String(ctx.forwardBody.length) };
  if (ctx.isCustom) delete finalHeaders['accept-encoding'];

  const transport = target.protocol === 'https:' ? https : http;
  const defaultPort = target.protocol === 'https:' ? 443 : 80;

  const proxyReq = transport.request(
    { hostname: target.hostname, port: target.port || defaultPort, path: target.pathname + target.search, method: ctx.req.method, headers: finalHeaders },
    (proxyRes) => handleProxyResponse({
      reqCtx: ctx, proxyRes, headers: finalHeaders, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit,
      forwardToUpstream: ({ ctx: fallbackCtx }) => forwardToUpstream({ ctx: fallbackCtx, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit }),
      onUpstreamResponse,
      onRetryNeeded
    })
  );

  // Track whether the client is still interested in a response.
  // When Claude Code gives up on a request and retries, it closes the
  // original connection. The upstream may still be running and eventually
  // timeout — we must NOT write a 400 to a dead response.
  let clientGone = false;
  const markClientGone = () => { clientGone = true; proxyReq.destroy(); };
  ctx.req.on('aborted', markClientGone);
  ctx.req.on('close', () => { if (!ctx.res.writableEnded) markClientGone(); });

  const upstreamTimeout = getConfig().upstreamTimeoutMs;
  if (upstreamTimeout > 0) {
    proxyReq.setTimeout(upstreamTimeout, () => {
      proxyReq.destroy(new Error(`Upstream timed out after ${upstreamTimeout}ms`)); // eslint-disable-line local/no-generic-error -- Node.js destroy() requires Error
    });
  }

  proxyReq.on('error', (err) => {
    const errorId = generateErrorId();

    // Check if retry wants to handle this TCP error
    if (onTcpError && onTcpError(err)) {
      emit(`[#${ctx.id}] ${errorId} Retriable TCP error: ${err.code}`, ctx.sessionId).catch(() => {});
      return;
    }

    // Use both the closure flag AND the live check — between retry attempts
    // the closure may be stale (close event already fired before new listeners
    // were registered), but ctx.clientAborted reads req.aborted/res.destroyed
    // live, catching the case where the client disconnected mid-retry.
    if (clientGone || ctx.clientAborted) {
      emit(`[#${ctx.id}] ${errorId} proxy_error (client gone): ${err.message}`, ctx.sessionId).catch(() => {});
      return;
    }

    const isQuietError = err.code === 'ECONNRESET' && (ctx.req.aborted || ctx.req.closed);

    if (!isQuietError) {
      errorReporter.write(err, { requestId: ctx.id, route: ctx.routeLabel, method: ctx.req.method, url: ctx.req.url, sessionId: ctx.sessionId, headers: finalHeaders });
    }

    emit(`[#${ctx.id}] ${errorId} proxy_error: ${err.message}`, ctx.sessionId).catch(() => {});

    if (!ctx.res.headersSent) ctx.res.writeHead(400, { 'content-type': 'application/json' });
    if (!ctx.res.writableEnded) ctx.res.end(JSON.stringify({ type: 'error', error: { type: 'proxy_error', message: `Upstream connection failed: ${err.message}`, error_id: errorId } }));
  });

  proxyReq.write(ctx.forwardBody);
  proxyReq.end();
}

/**
 * Handle the upstream proxy response: stream to client, apply SSE transformation
 * for non-compliant providers, and delegate to handleResponseEnd on completion.
 *
 * When the upstream returns an error (4xx/5xx) and the matched rule has a fallback,
 * buffers the error response and re-routes to the fallback provider instead.
 *
 * When retry is configured and the error matches retry criteria, buffers the
 * response and signals retry instead of streaming to the client.
 */
export function handleProxyResponse({ reqCtx, proxyRes, headers, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, forwardToUpstream, onUpstreamResponse, onRetryNeeded }) {
  if (reqCtx.clientAborted) {
    proxyRes.resume(); // drain the response
    return;
  }

  const statusCode = proxyRes.statusCode;
  const matchedRule = reqCtx.matchedRule;

  // ── Retry interception for error responses ──
  if (onUpstreamResponse && statusCode >= 400) {
    const errorChunks = [];
    proxyRes.on('data', (chunk) => errorChunks.push(chunk));
    proxyRes.on('end', () => {
      const bodyStr = Buffer.concat(errorChunks).toString('utf8');
      if (onUpstreamResponse(statusCode, bodyStr)) {
        if (onRetryNeeded) onRetryNeeded();
        return;
      }
      // Not retryable — fall through to fallback or normal streaming
      processProxyResponse(reqCtx, proxyRes, statusCode, headers, errorChunks, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, forwardToUpstream, matchedRule);
    });
    proxyRes.on('error', () => { if (!reqCtx.res.writableEnded && !reqCtx.clientAborted) reqCtx.res.end(); });
    return;
  }

  processProxyResponse(reqCtx, proxyRes, statusCode, headers, null, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, forwardToUpstream, matchedRule);
}

/**
 * Process an upstream response: fallback interception, streaming, SSE transformation.
 */
function processProxyResponse(reqCtx, proxyRes, statusCode, headers, bufferedChunks, handleResponseEnd, errorReporter, getConfig, policy, extensions, emit, forwardToUpstream, matchedRule) {
  // ── Fallback interception ──
  if (extensions && extensions.hasFallback && extensions.shouldAttemptFallback({ statusCode, matchedRule, fallbackDepth: reqCtx.fallbackDepth })) {
    const errorChunks = bufferedChunks ?? [];
    if (!bufferedChunks) {
      proxyRes.on('data', (chunk) => errorChunks.push(chunk));
    }

    const afterBuffer = () => {
      const fallbackResult = extensions.buildFallbackRequest({ originalBody: reqCtx.originalBody, matchedRule, policy, routedHeaders: reqCtx.routedHeaders });
      if (!fallbackResult) {
        streamBufferedError(reqCtx, proxyRes, errorChunks, handleResponseEnd, headers);
        return;
      }

      if (emit) {
        emit(`[#${reqCtx.id}] Fallback: ${reqCtx.routeLabel} \u2192 ${fallbackResult.label} [upstream ${statusCode}]`, reqCtx.sessionId).catch(() => {});
      }

      const fallbackCtx = reqCtx.withRouting({
        routeLabel: fallbackResult.label,
        reqModel: reqCtx.reqModel,
        sessionId: reqCtx.sessionId,
        routedHeaders: fallbackResult.routedHeaders,
        forwardBody: fallbackResult.forwardBody,
        targetBase: fallbackResult.targetBase,
        isCustom: true,
        rawBody: reqCtx.rawBody,
        originalBody: reqCtx.originalBody,
        sanitizationReport: fallbackResult.sanitizationReport,
        fallbackDepth: reqCtx.fallbackDepth + 1,
        matchedRule: null
      });

      forwardToUpstream({ ctx: fallbackCtx });
    };

    if (bufferedChunks) {
      afterBuffer();
    } else {
      proxyRes.on('end', afterBuffer);
    }
    proxyRes.on('error', () => {
      if (!reqCtx.res.headersSent && !reqCtx.clientAborted) {
        streamBufferedError(reqCtx, proxyRes, [], handleResponseEnd, headers);
      }
    });
    return;
  }

  // ── Normal streaming ──
  const isSse = (proxyRes.headers['content-type'] || '').includes('text/event-stream');
  const shouldTransform = reqCtx.isCustom && isSse;

  // If we already buffered the response (from retry check), stream it directly
  if (bufferedChunks) {
    streamBufferedResponse(reqCtx, proxyRes, bufferedChunks, handleResponseEnd, headers);
    return;
  }

  const resHeaders = filterResponseHeaders(proxyRes.headers);
  if (shouldTransform) {
    delete resHeaders['content-encoding'];
    delete resHeaders['content-length'];
  }

  if (reqCtx.clientAborted) return;
  reqCtx.res.writeHead(proxyRes.statusCode, resHeaders);

  reqCtx.res.on('error', (err) => {
    if (err.code === 'ECONNRESET') return;
    errorReporter.write(err, { requestId: reqCtx.id, operation: 'writing to client response' });
  });

  const resChunks = [];

  if (shouldTransform) {
    const transformer = new SseResponseTransformer(extensions);
    proxyRes.on('data', (chunk) => {
      if (reqCtx.clientAborted) return;
      const transformedStr = transformer.transformChunk(chunk.toString('utf8'));
      if (transformedStr) {
        const buf = Buffer.from(transformedStr, 'utf8');
        resChunks.push(buf);
        if (!reqCtx.clientAborted) reqCtx.res.write(buf);
      }
    });
    proxyRes.on('end', () => {
      if (reqCtx.clientAborted) return;
      const rest = transformer.flush();
      if (rest) {
        const buf = Buffer.from(rest, 'utf8');
        resChunks.push(buf);
        if (!reqCtx.clientAborted) reqCtx.res.write(buf);
      }
      const resCtx = new ProxyResponseContext({
        proxyRes, res: reqCtx.res, id: reqCtx.id, startTime: reqCtx.startTime,
        routeLabel: reqCtx.routeLabel, reqModel: reqCtx.reqModel, sessionId: reqCtx.sessionId,
        headers, req: reqCtx.req, isCustom: reqCtx.isCustom, rawBody: reqCtx.rawBody, forwardBody: reqCtx.forwardBody,
        sanitizationReport: reqCtx.sanitizationReport
      });
      handleResponseEnd({ resCtx, resChunks });
    });
    proxyRes.on('error', () => { if (!reqCtx.res.writableEnded && !reqCtx.clientAborted) reqCtx.res.end(); });
  } else {
    proxyRes.on('data', (chunk) => {
      resChunks.push(chunk);
      if (!reqCtx.clientAborted) reqCtx.res.write(chunk);
    });
    proxyRes.on('error', () => { if (!reqCtx.res.writableEnded && !reqCtx.clientAborted) reqCtx.res.end(); });

    proxyRes.on('end', () => {
      if (reqCtx.clientAborted) return;
      const resCtx = new ProxyResponseContext({
        proxyRes, res: reqCtx.res, id: reqCtx.id, startTime: reqCtx.startTime,
        routeLabel: reqCtx.routeLabel, reqModel: reqCtx.reqModel, sessionId: reqCtx.sessionId,
        headers, req: reqCtx.req, isCustom: reqCtx.isCustom, rawBody: reqCtx.rawBody, forwardBody: reqCtx.forwardBody,
        sanitizationReport: reqCtx.sanitizationReport
      });
      handleResponseEnd({ resCtx, resChunks });
    });
  }
}

/**
 * Stream a buffered response to the client (used after retry/fallback buffering).
 */
function streamBufferedResponse(reqCtx, proxyRes, chunks, handleResponseEnd, headers) {
  if (reqCtx.clientAborted) return;

  if (reqCtx.res.headersSent) {
    if (!reqCtx.res.writableEnded) reqCtx.res.end();
    return;
  }
  const resHeaders = filterResponseHeaders(proxyRes.headers);
  reqCtx.res.writeHead(proxyRes.statusCode, resHeaders);
  for (const chunk of chunks) {
    reqCtx.res.write(chunk);
  }

  const resCtx = new ProxyResponseContext({
    proxyRes, res: reqCtx.res, id: reqCtx.id, startTime: reqCtx.startTime,
    routeLabel: reqCtx.routeLabel, reqModel: reqCtx.reqModel, sessionId: reqCtx.sessionId,
    headers, req: reqCtx.req, isCustom: reqCtx.isCustom, rawBody: reqCtx.rawBody, forwardBody: reqCtx.forwardBody,
    sanitizationReport: reqCtx.sanitizationReport
  });
  handleResponseEnd({ resCtx, resChunks: chunks });
}

/**
 * Stream a buffered upstream error to the client when fallback is not possible.
 */
function streamBufferedError(reqCtx, proxyRes, chunks, handleResponseEnd, headers) {
  if (reqCtx.clientAborted) return;

  if (reqCtx.res.headersSent) {
    if (!reqCtx.res.writableEnded) reqCtx.res.end();
    return;
  }
  const resHeaders = filterResponseHeaders(proxyRes.headers);
  reqCtx.res.writeHead(proxyRes.statusCode, resHeaders);
  for (const chunk of chunks) {
    reqCtx.res.write(chunk);
  }
  reqCtx.res.end();
}

import { ANTHROPIC_HOST } from './headers.js';
import { RoutingResult, Option } from './types.js';
import { getModel, getMessages } from './api-adapter.js';

/**
 * Route to Anthropic's API directly (no custom provider match).
 */
export function routeToAnthropic(body, anthropicBaseUrl = `https://${ANTHROPIC_HOST}`) {
  const modelStr = getModel(body);
  return new RoutingResult({
    forwardBody: Buffer.from(JSON.stringify(body)),
    targetBase: anthropicBaseUrl,
    label: `Anthropic (${modelStr})`,
    isCustom: false,
    sanitizationReport: { convertedCount: 0, convertedTypes: [] }
  });
}

/**
 * Route to a matched custom provider.
 *
 * Runs extension request transforms (sanitization, non-compliant transform,
 * web search, etc.) on the body, then builds the RoutingResult.
 */
export function routeToProvider(body, match, extensions) {
  const { provider, realModel, label } = match;

  let extBody = { ...body, model: realModel };
  if (extensions && extensions.requestTransformerCount > 0) {
    extBody = extensions.transformRequest({ body: extBody, provider, isCompliant: provider.anthropicCompliant });
  }

  const report = extBody._ccbSanitizationReport ?? { convertedCount: 0, convertedTypes: [] };
  const { _ccbSanitizationReport: _, ...cleanBody } = extBody;

  return new RoutingResult({
    forwardBody: Buffer.from(JSON.stringify(cleanBody)),
    targetBase: provider.url,
    label: `Provider (${label})`,
    isCustom: true,
    sanitizationReport: report
  });
}

export function applyRouting(body, providersMap, anthropicBaseUrl) {
  if (typeof body.model !== 'string') return routeToAnthropic(body, anthropicBaseUrl);

  const match = providersMap.resolve(body.model);
  if (!match) return routeToAnthropic(body, anthropicBaseUrl);

  return routeToProvider(body, match);
}

export function applyRoutingWithMatch(body, matchOpt, anthropicBaseUrl, extensions) {
  if (typeof body.model !== 'string') return routeToAnthropic(body, anthropicBaseUrl);
  if (matchOpt.isNone) return routeToAnthropic(body, anthropicBaseUrl);
  return routeToProvider(body, matchOpt.value, extensions);
}

export function applyAuthHeaders({ headers, match, apiKey = '' }) {
  if (!match) return { ...headers };

  const { provider } = match;
  const { authorization: _, 'anthropic-beta': beta, ...rest } = headers;
  const updated = { ...rest };

  if (provider.id && apiKey) {
    updated['x-api-key'] = apiKey;
  }

  if (provider.anthropicCompliant && beta !== undefined) {
    updated['anthropic-beta'] = beta;
  }

  return updated;
}

function tryParseUserId(userIdStr) {
  if (typeof userIdStr !== 'string') return Option.none();
  try {
    const parsed = JSON.parse(userIdStr);
    if (!parsed.session_id) return Option.none();
    return Option.some(parsed.session_id);
  } catch {
    return Option.none();
  }
}

export function extractSessionId(body) {
  if (!body) return '';

  const userIdStr = body.metadata?.user_id;
  const parsedUserId = tryParseUserId(userIdStr);

  if (parsedUserId.isSome) return parsedUserId.value;

  if (body.metadata?.session_id) return body.metadata.session_id;
  if (body.session_id) return body.session_id;

  return '';
}

export function tryParseBody(rawBody) {
  if (!rawBody) return Option.none();
  if (rawBody.length === 0) return Option.none();

  try {
    return Option.some(JSON.parse(rawBody.toString()));
  } catch {
    return Option.none();
  }
}

/**
 * Fallback extension for provider failover.
 *
 * When an upstream provider returns an error (4xx/5xx) or a TCP connection
 * fails, this extension decides whether to re-route the request to a
 * fallback provider and builds the fallback request.
 *
 * Configuration comes from the routing rule's `fallback` field:
 *   { fallbackProviderId, fallbackModel, hasFallback }
 */

import { Option } from '../core/types.js';
import { ProviderMatch } from '../core/providers.js';
import { providerIdToEnvKey } from '../core/providers.js';
import { MAX_FALLBACK_DEPTH } from '../core/routing-rules.js';
import { tryParseBody, routeToProvider, applyAuthHeaders } from '../core/routing.js';

export function createFallbackExtension() {
  return {
    name: 'fallback',

    hooks: {
      shouldAttemptFallback: {
        order: 50,
        check: ({ statusCode, matchedRule, fallbackDepth }) =>
          checkFallback(statusCode, matchedRule, fallbackDepth),
      },
      shouldAttemptFallbackForTcpError: {
        order: 50,
        check: ({ matchedRule, fallbackDepth }) =>
          checkFallbackForTcpError(matchedRule, fallbackDepth),
      },
      buildFallbackRequest: {
        order: 50,
        build: ({ originalBody, matchedRule, policy, routedHeaders }) =>
          buildFallbackRequest(originalBody, matchedRule, policy, routedHeaders),
      },
    },
  };
}

function checkFallback(statusCode, matchedRule, fallbackDepth) {
  if (!matchedRule) return false;
  if (!matchedRule.hasFallback) return false;
  if (statusCode < 400) return false;
  if (fallbackDepth >= MAX_FALLBACK_DEPTH) return false;
  return true;
}

function checkFallbackForTcpError(matchedRule, fallbackDepth) {
  if (!matchedRule) return false;
  if (!matchedRule.hasFallback) return false;
  if (fallbackDepth >= MAX_FALLBACK_DEPTH) return false;
  return true;
}

function buildFallbackRequest(originalBody, matchedRule, policy, routedHeaders) {
  const providerOpt = policy.getProvider(matchedRule.fallbackProviderId);
  if (providerOpt.isNone) return null;

  const fallbackMatch = new ProviderMatch(providerOpt.value, `fallback:${matchedRule.toLabel()}`, matchedRule.fallbackModel);
  const bodyOpt = tryParseBody(originalBody);
  if (bodyOpt.isNone) return null;

  const body = bodyOpt.value;
  const bodyWithFallbackModel = { ...body, model: fallbackMatch.realModel };
  const routing = routeToProvider(bodyWithFallbackModel, fallbackMatch);

  const envVar = providerIdToEnvKey(fallbackMatch.provider.id);
  const apiKey = process.env[envVar] ?? '';
  const finalHeaders = applyAuthHeaders({ headers: routedHeaders, match: fallbackMatch, apiKey });

  return {
    forwardBody: routing.forwardBody,
    routedHeaders: finalHeaders,
    targetBase: routing.targetBase,
    label: `Fallback (${fallbackMatch.label})`,
    sanitizationReport: routing.sanitizationReport
  };
}

/**
 * Sanitization extension for multi-provider routing.
 *
 * Converts Anthropic-specific block types (thinking, redacted_thinking,
 * connector_text) to text blocks when switching between providers.
 * Compliant providers (Anthropic) preserve signed thinking blocks;
 * non-compliant providers strip all thinking blocks regardless.
 *
 * Also sanitizes tool_result content arrays (non-compliant only) and
 * strips cache_control from generic blocks (non-compliant only).
 */

import { BLOCK_TYPES } from '../core/types.js';
import {
  getSystemBlockText,
  getBlockType, getBlockText, getBlockThinking, getBlockRedactedData, getBlockToolContent,
  hasValidSignature, omitCacheControl,
  getSystem, getMessages,
} from '../core/api-adapter.js';

export function createSanitizationExtension() {
  return {
    name: 'sanitization',

    hooks: {
      requestTransform: {
        order: 5,
        transform: ({ body, provider }) => transformSanitize(body, provider?.anthropicCompliant ?? false),
      },
    },
  };
}

function transformSanitize(body, isCompliant) {
  const system = getSystem(body);
  const messages = getMessages(body);
  if (!messages && !system) return body;

  let report = { convertedCount: 0, convertedTypes: [] };

  let safeSystem = system;
  if (system !== undefined && system !== null) {
    const result = sanitizeContent(system, isCompliant);
    safeSystem = result.content;
    report.convertedCount += result.conversions.length;
    report.convertedTypes = [...new Set([...report.convertedTypes, ...result.conversions])];
  }

  let safeMessages = messages;
  if (Array.isArray(messages)) {
    const result = sanitizeMessages(messages, isCompliant);
    safeMessages = result.messages;
    report = mergeReports(report, result.report);
  }

  return { ...body, system: safeSystem, messages: safeMessages, _ccbSanitizationReport: report };
}

function mergeReports(a, b) {
  return {
    convertedCount: a.convertedCount + b.convertedCount,
    convertedTypes: [...new Set([...a.convertedTypes, ...b.convertedTypes])],
  };
}

function sanitizeMessages(messages, isCompliant) {
  const allConversions = [];
  const sanitized = messages.map(m => {
    const { message, conversions } = sanitizeMessage(m, isCompliant);
    allConversions.push(...conversions);
    return message;
  });
  return { messages: sanitized, report: { convertedCount: allConversions.length, convertedTypes: [...new Set(allConversions)] } };
}

function sanitizeMessage(m, isCompliant) {
  if (!m || typeof m !== 'object') return { message: m, conversions: [] };
  const { content, conversions } = sanitizeContent(m.content, isCompliant);
  return { message: { ...m, content }, conversions };
}

function sanitizeContent(content, isCompliant) {
  if (typeof content === 'string') return { content, conversions: [] };
  if (Array.isArray(content)) {
    const conversions = [];
    const safeBlocks = content.map(b => {
      const { block, converted, originalType } = sanitizeBlock(b, isCompliant);
      if (converted) conversions.push(originalType);
      return block;
    });
    return { content: mergeAdjacentTextBlocks(safeBlocks), conversions };
  }
  if (typeof content === 'object' && content !== null) {
    const { block, converted, originalType } = sanitizeBlock(content, isCompliant);
    return { content: block, conversions: converted ? [originalType] : [] };
  }
  return { content, conversions: [] };
}

function sanitizeBlock(block, isCompliant) {
  if (typeof block !== 'object' || block === null) return { block, converted: false };

  const originalType = getBlockType(block);
  let result;

  const blockHandlers = {
    [BLOCK_TYPES.THINKING]: () => sanitizeThinkingBlock(block, isCompliant),
    [BLOCK_TYPES.REDACTED_THINKING]: () => sanitizeRedactedThinking(block, isCompliant),
    [BLOCK_TYPES.CONNECTOR_TEXT]: () => sanitizeConnectorText(block, isCompliant),
    [BLOCK_TYPES.TOOL_RESULT]: () => !isCompliant ? sanitizeToolResult(block) : null,
  };

  const handler = blockHandlers[originalType];
  result = handler ? handler() : null;
  if (result === null) result = sanitizeGenericBlock(block, isCompliant);

  const converted = result.type !== originalType;
  return { block: result, converted, originalType: converted ? originalType : undefined };
}

function sanitizeThinkingBlock(block, isCompliant) {
  if (isCompliant && hasValidSignature(block)) return block;
  return { type: BLOCK_TYPES.TEXT, text: `\`\`\`thinking\n${getBlockThinking(block)}\n\`\`\`\n` };
}

function sanitizeRedactedThinking(block, isCompliant) {
  if (isCompliant && hasValidSignature(block)) return block;
  const data = getBlockRedactedData(block) || '[Redacted Thinking]';
  return { type: BLOCK_TYPES.TEXT, text: `\`\`\`thinking\n${data}\n\`\`\`\n` };
}

function sanitizeConnectorText(block, isCompliant) {
  if (isCompliant && hasValidSignature(block)) return block;
  return { type: BLOCK_TYPES.TEXT, text: `[Connector Text]\n${getBlockText(block)}` };
}

function sanitizeToolResult(block) {
  const rest = omitCacheControl(block);
  const toolContent = getBlockToolContent(rest);
  if (!Array.isArray(toolContent)) return rest;
  const joinedContent = toolContent.map(extractToolResultText).join('\n');
  return { ...rest, content: joinedContent };
}

function sanitizeGenericBlock(block, isCompliant) {
  if (isCompliant) return block;
  return omitCacheControl(block);
}

function extractToolResultText(block) {
  if (typeof block === 'string') return block;
  const text = getBlockText(block);
  if (text) return text;
  return JSON.stringify(block);
}

function mergeAdjacentTextBlocks(blocks) {
  const merged = [];
  for (const block of blocks) {
    const last = merged[merged.length - 1];
    if (last && last.type === 'text' && block.type === 'text') {
      last.text = (last.text || '') + '\n' + (block.text || '');
      continue;
    }
    merged.push({ ...block });
  }
  return merged;
}

import fs from 'fs';
import path from 'path';
import { redactHeaders } from '../core/headers.js';
import { parseSseMetadata } from '../core/sse-parser.js';
import { RequestSummary } from '../core/types.js';
import { decompress } from '../core/compression.js';

export class Logger {
  #logsDir;
  #defaultLog;
  #history;
  #maxHistory;

  constructor({ logsDir, defaultLog, maxHistory }) {
    this.#logsDir = logsDir;
    this.#defaultLog = defaultLog;
    this.#history = [];
    this.#maxHistory = maxHistory;
  }

  async emit(line, sessionId) {
    const out = line + '\n';
    process.stdout.write(out);
    try {
      if (!fs.existsSync(this.#logsDir)) fs.mkdirSync(this.#logsDir, { recursive: true });
      const logPath = sessionId
        ? path.join(this.#logsDir, `session-${sessionId}.log`)
        : this.#defaultLog;
      await fs.promises.appendFile(logPath, out);
    } catch { /* best effort */ }
  }

  async logRequest(requestInfo, config) {
    if (!config.loggingEnabled || !config.logRequests) return;
    const { id, route, url, contentLength, messageCount, sessionId } = requestInfo;
    await this.emit(`[REQ #${id}] → ${route} ${url} | ${contentLength} bytes | ${messageCount} messages`, sessionId);

    if (config.maxBodyLog <= 0) return;
    await this.emit(`Headers: ${JSON.stringify(redactHeaders(requestInfo.headers), null, 2)}`, sessionId);
    const bodyStr = JSON.stringify(requestInfo.body, null, 2);
    const truncated = bodyStr.length > config.maxBodyLog
      ? bodyStr.slice(0, config.maxBodyLog) + `\n... [truncated, ${bodyStr.length} chars total]`
      : bodyStr;
    await this.emit(`Body: ${truncated}`, sessionId);
  }

  async logResponse(id, statusCode, headers, rawBody, sessionId, config) {
    if (!config.loggingEnabled || !config.logResponses) return;
    const isSse = (headers['content-type'] ?? '').includes('text/event-stream');

    if (isSse) return this.#logSseResponse(id, statusCode, rawBody, sessionId);
    return this.#logJsonResponse(id, statusCode, rawBody, sessionId, config);
  }

  async #logSseResponse(id, statusCode, raw, sessionId) {
    const meta = parseSseMetadata(raw);
    const blockSummary = meta.blocks.map((b) => b.toSummary()).join(', ');
    const tokenInfo = `in:${meta.inputTokens} out:${meta.outputTokens}`;
    await this.emit(`[RES #${id}] ← ${statusCode} | ${tokenInfo} | blocks: ${blockSummary || 'none'}`, sessionId);
    for (const b of meta.blocks) {
      // Note: signature may be empty at content_block_start time for streaming responses.
      // Anthropic attaches real signatures later in the stream. Empty here ≠ unsigned.
      await this.emit(`  block: ${JSON.stringify({ type: b.type, name: b.name, signature: b.signature || '(stream-start)' })}`, sessionId);
    }
    if (meta.hasError) {
      await this.emit(`[RES #${id}] SSE error: ${JSON.stringify(meta.error)}`, sessionId);
    }
  }

  async #logJsonResponse(id, statusCode, raw, sessionId, config) {
    let detail = '';
    try {
      const parsed = JSON.parse(raw);
      if (parsed.error) detail = ` | error: ${parsed.error.type ?? 'unknown'} "${parsed.error.message}"`;
    } catch { }
    await this.emit(`[RES #${id}] ← ${statusCode}${detail}`, sessionId);

    if (config.maxBodyLog <= 0) return;
    const truncated = raw.length > config.maxBodyLog
      ? raw.slice(0, config.maxBodyLog) + `\n... [truncated, ${raw.length} chars total]`
      : raw;
    await this.emit(`Body: ${truncated}`, sessionId);
  }

  addSummary(summary) {
    this.#history.push(summary);
    while (this.#history.length > this.#maxHistory) this.#history.shift();
  }

  getHistory() { return Object.freeze([...this.#history]); }

  async decompressChunks(chunks, encoding) {
    const buffer = Buffer.concat(chunks);
    const res = await decompress(buffer, encoding);
    return res.isSuccess ? res.value.toString() : buffer.toString();
  }
}

import http from 'http';
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs';
import { createProxyCore } from './proxy-core.js';
import { loadConfigFromFile, resolveUserConfigDir } from './core/config.js';

const USER_CONFIG_DIR = resolveUserConfigDir();
const config = loadConfigFromFile(USER_CONFIG_DIR);
const PORT = config.port;

const core = createProxyCore({ configDir: USER_CONFIG_DIR, port: PORT });
core.initProviders();

const server = http.createServer(core.createRequestHandler());

server.listen(PORT, async () => {
  const pidsFile = path.join(core.logsDir, 'proxy.pids');
  if (!fs.existsSync(core.logsDir)) fs.mkdirSync(core.logsDir, { recursive: true });
  fs.writeFileSync(pidsFile, process.pid + '\n', 'utf8');

  const cfg = await core.getConfig();
  await core.emit(`CC-Bridge proxy listening on http://localhost:${PORT}`);
  await core.emit(`Logging: ${cfg.loggingEnabled ? 'ON' : 'OFF'} | logs dir: ${core.logsDir}`);
  await core.emit(`Providers: ${core.providerCount} route(s) loaded`);
});
